      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_INPUT', 'Name is required');
  }
  try {
    const project = await projectsService.createProject(name);
    res.status(201).json({ project });
  } catch (error) {
    if (error.code === 'DUPLICATE_PROJECT') {
      return sendError(res, 409, 'DUPLICATE_PROJECT', 'Project already exists');
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;"
    },
    {
      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projectsStore = [];

async function getAllProjects() {
  return projectsStore.slice();
}

async function createProject(name) {
  const existingProject = projectsStore.find(project => project.name === name);
  if (existingProject) {
    throw { code: 'DUPLICATE_PROJECT' };
  }
  const newProject = { id: randomUUID(), name };
  projectsStore.push(newProject);
  return newProject;
}

module.exports = {
  getAllProjects,
  createProject,
};"
