      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    const tasks = await tasksService.getAllTasks(req.params.projectId);
    if (status === 'done') {
      return res.json({ tasks: tasks.filter(task => task.status === 'done') });
    }
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
  }
  try {
    const updatedTask = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
    if (!updatedTask) {
      return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    }
    res.json({ task: updatedTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;"
    },
    {
      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const tasksStore = [];

async function getAllTasks(projectId) {
  return tasksStore.filter(task => task.projectId === projectId);
}

async function updateTaskStatus(projectId, taskId, status) {
  const taskIndex = tasksStore.findIndex(task => task.id === taskId && task.projectId === projectId);
  if (taskIndex === -1) {
    return null;
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

module.exports = {
  getAllTasks,
  updateTaskStatus,
};"
