      "content": "const { randomUUID } = require('node:crypto');
const commentsStore = [];

async function addComment(projectId, taskId, message) {
  const newComment = { id: randomUUID(), projectId, taskId, message };
  commentsStore.push(newComment);
  return newComment;
}

async function getAllComments(projectId, taskId) {
  return commentsStore.filter(comment => comment.projectId === projectId && comment.taskId === taskId);
}

module.exports = {
  addComment,
  getAllComments,
};"
